const scores = $('Get Scores').all();
const notesDb = $('Get All Notes Pages').all();

const getProp = (item, names) => {
  for (const name of names) {
    if (item.json[name] !== undefined) return item.json[name];
    if (item.json.properties?.[name] !== undefined) {
       const p = item.json.properties[name];
       if (p === null) return '';
       if (p.type === 'rich_text') return p.rich_text.map(r => r.plain_text).join('');
       if (p.type === 'title') return p.title.map(r => r.plain_text).join('');
       if (p.type === 'checkbox') return p.checkbox;
       if (p.type === 'email') return p.email;
       if (p.type === 'date') return p.date?.start || '';
       if (p.type === 'select') return p.select?.name || '';
       return p;
    }
  }
  return '';
};

const deletedTopicsByUser = new Map();

for (const item of notesDb) {
  const username = String(getProp(item, ['Username', 'username']) || '').trim().toLowerCase();
  const topic = String(getProp(item, ['Subject-name', 'Topic', 'topic']) || '').trim();
  const deleted = Boolean(getProp(item, ['Deleted', 'deleted']));

  if (!username || !topic || !deleted) continue;

  if (!deletedTopicsByUser.has(username)) {
    deletedTopicsByUser.set(username, new Set());
  }
  deletedTopicsByUser.get(username).add(topic.toLowerCase());
}

const byUser = {};

for (const item of scores) {
  const username = String(getProp(item, ['property_username', 'Username', 'username']) || '').trim().toLowerCase();
  const email = String(getProp(item, ['property_email', 'Email', 'email']) || '').trim().toLowerCase();
  const topic = String(getProp(item, ['property_topic', 'Topic', 'topic']) || '').trim();
  const weakTopicsRaw = String(getProp(item, ['property_weaktopics', 'property_weak_topics', 'Weak Topics', 'weak_topics', 'weakTopics']) || '').trim();
  const lastAttempt = String(getProp(item, ['property_lastattempt', 'property_last_attempt', 'Last Attempt', 'last_attempt', 'lastAttempt']) || '');

  if (!username || !email || !weakTopicsRaw) continue;

  const deletedTopics = deletedTopicsByUser.get(username) || new Set();
  if (topic && deletedTopics.has(topic.toLowerCase())) continue;

  const weakTopics = weakTopicsRaw.split(',').map((t) => t.trim()).filter(Boolean);
  if (!weakTopics.length) continue;

  if (!byUser[email]) {
    byUser[email] = {
      username,
      email,
      latestAttempt: lastAttempt || '',
      topics: new Set(),
      weakTopics: new Set()
    };
  }

  if (
    lastAttempt &&
    (!byUser[email].latestAttempt || new Date(lastAttempt) > new Date(byUser[email].latestAttempt))
  ) {
    byUser[email].latestAttempt = lastAttempt;
  }

  if (topic) byUser[email].topics.add(topic);
  weakTopics.forEach((wt) => byUser[email].weakTopics.add(wt));
}

return Object.values(byUser).map((user) => {
  const weakTopics = Array.from(user.weakTopics).slice(0, 6);
  const topics = Array.from(user.topics).slice(0, 3);

  return {
    json: {
      email: user.email,
      username: user.username,
      subject: 'Time to revise your weak topics',
      message: `Hi ${user.username},\n\nIt is time to come back and study. Based on your recent quiz performance, here are the weak topics you should revise today:\n\n- ${weakTopics.join('\n- ')}\n\nRecent study areas: ${topics.join(', ') || 'your saved topics'}\n\nA short revision session today will help strengthen these concepts.\n\nYour Smart Study Assistant`
    }
  };
});
